class Stack:
    def __init__(self, initial_capacity: int = 8) -> None:
        self._arr: list[int] = [0] * initial_capacity
        self._top: int = -1
        self._capacity: int = initial_capacity

    def push(self, x: int) -> None:
        if self._top == self._capacity - 1:
            self._arr = self._arr + [0] * self._capacity  # double
            self._capacity *= 2
        self._top += 1
        self._arr[self._top] = x

    def pop(self) -> int:
        if self.is_empty():
            raise IndexError('Stack is empty')
        val = self._arr[self._top]
        self._top -= 1
        return val

    def peek(self) -> int:
        if self.is_empty():
            raise IndexError('Stack is empty')
        return self._arr[self._top]

    def is_empty(self) -> bool:
        return self._top == -1

    def size(self) -> int:
        return self._top + 1
